module RefModule(clock, c_in, d_in, out1);// SIGNAL DECLARATIONS
input clock;
input c_in;
input d_in;
output out1;
reg out1;
reg temp;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clock or posedge dbg_halt)
begin
	out1 <= temp - d_in;
	temp <= c_in - d_in;
end

endmodule
